  ('elementary-f29af906-moex-00538', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依地方制度法之規定，縣（市）政府為辦理上級機關委辦事項，依其法定職權所訂定之委辦規則與 憲法牴觸者，由下列何者予以函告無效？', '["法務部", "委辦機關", "司法院憲法法庭", "地方立法機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00539', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '為保障民眾不動產交易安全，若直轄市或縣（市）擬立法規範不動產相關管理事項，對違反規定之 不動產業者進行裁罰，其應以下列何種自治法規為之？', '["自律規則", "委辦規則", "自治規則", "自治條例"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00540', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關行政主體及行政機關之敘述，下列何者錯誤？', '["行政機關，係指代表國家、地方自治團體或其他行政主體表示意思，從事公共事務，具有單獨法 定地位之組織", "行政主體在行政法上享有權利、負擔義務，具有一定職權，且得設置機關以便行使，並實現行政 上任務", "鄉公所以及縣政府、直轄市等都屬於行政機關", "國家、直轄市山地原住民區、行政法人等都屬於行政主體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00541', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '公職人員執行職務時，得因其作為或不作為，直接或間接使本人或其關係人獲取利益者，即屬於利 益衝突。有關利益衝突之敘述，下列何者正確？', '["公職人員有利益衝突者，經長官裁決後，始需迴避", "公職人員不得假借職務上之權力、機會或方法，圖本人之利益。但關係人之利益不在此限", "公職人員之關係人並非屬機關人員，故無關說、請託或以其他不當方法圖得利益之禁止問題", "公職人員或其關係人，皆不得與公職人員服務之機關或受其監督之機關為買賣、租賃、承攬等交 易行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00542', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依區域計畫法之規定，違反該法第15條第1項之管制使用土地，處新臺幣6萬元以上30萬元以下 罰鍰，但機關內部決定不論個案情節輕重，一律課6萬元罰鍰。此稱為下列何者？', '["裁量怠惰", "裁量逾越", "裁量選擇", "裁量濫用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00543', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關測量之辦理機關，下列何者錯誤？', '["地籍測量如用航空攝影測量，應由中央地政機關統籌辦理", "辦理異議複丈業務，得由主管機關委任所屬登記機關辦理之", "基本控制測量由國土測繪法之直轄市、縣（市）主管機關辦理，加密控制測量由國土測繪法之中 央主管機關辦理", "土地複丈及建築改良物測量之業務，由土地所在地之直轄市或縣（市）登記機關辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00544', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依地籍測量實施規則規定，有關地籍調查之規定，下列敘述何者正確？', '["土地所有權人因故不能到場指界、設立界標時，由測量人員優先以舊有地籍圖指界", "共有土地之界址，經共有人過半數及其應有部分合計過半數同意者，得由共有人中一人代表指界", "共有土地為公寓大廈基地並設有管理委員會者，應由公寓大廈管理委員會到場指界", "因法院拍賣而取得之土地，尚未登記完畢者，權利人得到場指界"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00545', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '借用測繪業登記證者，依法處新臺幣多少之罰鍰？', '["3萬元以上15萬元以下", "5萬元以上25萬元以下", "6萬元以上30萬元以下", "10萬元以上50萬元以下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00546', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地法規定，土地登記損害賠償之請求，如經該地政機關拒絕，受損害人如何處理？', '["得提起訴願", "得向司法機關起訴", "得逕提起行政訴訟", "得向直轄市、縣（市）政府申請調解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00547', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地登記規則規定，除繼承登記以外之土地權利變更登記，應於權利變更之日起1個月內申請之。 有關前開「權利變更之日」，下列敘述何者錯誤？', '["法院判決確定之日", "依鄉鎮市調解條例規定成立之調解，調解成立之日", "依仲裁法作成之判斷，判斷書交付或送達之日", "產權移轉證明文件核發之日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
